/*
 * iolib.c - YFS client library
 *
 * Maintains per-process state:
 *   - fd table (up to MAX_OPEN_FILES open files)
 *   - current working directory inode number
 *
 * Each function packages a request message and calls Send(-FILE_SERVER, &msg).
 * The reply is received when Send returns.
 */

#include <string.h>
#include <stdint.h>

#include <comp421/yalnix.h>
#include <comp421/iolib.h>
#include <comp421/filesystem.h>

#include "yfs_msg.h"

/* -----------------------------------------------------------------------
 * Library state
 * ----------------------------------------------------------------------- */

struct fd_entry {
    int  inum;      /* inode number of the open file */
    int  reuse;     /* reuse count when file was opened */
    int  position;  /* current byte position */
    int  is_open;   /* 1 if slot is in use */
};

static struct fd_entry fd_table[MAX_OPEN_FILES];
static int cwd_inum = ROOTINODE;   /* current directory inode */
static int lib_initialized = 0;

static void
lib_init(void)
{
    int i;
    if (lib_initialized) return;
    for (i = 0; i < MAX_OPEN_FILES; i++)
        fd_table[i].is_open = 0;
    cwd_inum = ROOTINODE;
    lib_initialized = 1;
}

/* Allocate the lowest available fd, return -1 if none available */
static int
alloc_fd(void)
{
    int i;
    lib_init();
    for (i = 0; i < MAX_OPEN_FILES; i++) {
        if (!fd_table[i].is_open)
            return i;
    }
    return -1;
}

/* Send a request and get back a reply. Returns the reply. */
static struct yfs_reply
do_request(struct yfs_msg *msg)
{
    struct yfs_reply reply;
    memset(&reply, 0, sizeof(reply));
    reply.retval = ERROR;

    Send(msg, -FILE_SERVER);
    /* After Send returns, the reply has been written into msg's space.
     * Actually, Send overwrites the 32 bytes at msg with the reply. */
    memcpy(&reply, msg, sizeof(reply));
    return reply;
}

/* -----------------------------------------------------------------------
 * Open
 * ----------------------------------------------------------------------- */
int
Open(char *pathname)
{
    struct yfs_msg msg;
    struct yfs_reply rep;
    int fd;

    lib_init();
    if (pathname == NULL) return ERROR;

    fd = alloc_fd();
    if (fd < 0) return ERROR;

    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_OPEN;
    msg.arg1 = cwd_inum;
    msg.arg2 = (int)strlen(pathname) + 1; /* include null terminator */
    msg.arg3 = 0;
    msg.ptr1 = pathname;
    msg.ptr2 = NULL;

    rep = do_request(&msg);
    if (rep.retval == ERROR) return ERROR;

    fd_table[fd].inum     = rep.inum;
    fd_table[fd].reuse    = rep.reuse;
    fd_table[fd].position = 0;
    fd_table[fd].is_open  = 1;
    return fd;
}

/* -----------------------------------------------------------------------
 * Close
 * ----------------------------------------------------------------------- */
int
Close(int fd)
{
    lib_init();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_open)
        return ERROR;
    fd_table[fd].is_open = 0;
    return 0;
}

/* -----------------------------------------------------------------------
 * Create
 * ----------------------------------------------------------------------- */
int
Create(char *pathname)
{
    struct yfs_msg msg;
    struct yfs_reply rep;
    int fd;

    lib_init();
    if (pathname == NULL) return ERROR;

    fd = alloc_fd();
    if (fd < 0) return ERROR;

    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_CREATE;
    msg.arg1 = cwd_inum;
    msg.arg2 = (int)strlen(pathname) + 1;
    msg.arg3 = 0;
    msg.ptr1 = pathname;
    msg.ptr2 = NULL;

    rep = do_request(&msg);
    if (rep.retval == ERROR) return ERROR;

    fd_table[fd].inum     = rep.inum;
    fd_table[fd].reuse    = rep.reuse;
    fd_table[fd].position = 0;
    fd_table[fd].is_open  = 1;
    return fd;
}

/* -----------------------------------------------------------------------
 * Read
 * ----------------------------------------------------------------------- */
int
Read(int fd, void *buf, int size)
{
    struct yfs_msg msg;
    struct yfs_reply rep;

    lib_init();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_open)
        return ERROR;
    if (buf == NULL || size < 0) return ERROR;
    if (size == 0) return 0;

    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_READ;
    msg.arg1 = fd_table[fd].inum;
    msg.arg2 = fd_table[fd].reuse;
    msg.arg3 = fd_table[fd].position;
    msg.ptr1 = buf;
    msg.ptr2 = (void *)(intptr_t)size;

    rep = do_request(&msg);
    if (rep.retval == ERROR) return ERROR;

    fd_table[fd].position = rep.newpos;
    return rep.retval; /* bytes read */
}

/* -----------------------------------------------------------------------
 * Write
 * ----------------------------------------------------------------------- */
int
Write(int fd, void *buf, int size)
{
    struct yfs_msg msg;
    struct yfs_reply rep;

    lib_init();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_open)
        return ERROR;
    if (buf == NULL || size < 0) return ERROR;
    if (size == 0) return 0;

    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_WRITE;
    msg.arg1 = fd_table[fd].inum;
    msg.arg2 = fd_table[fd].reuse;
    msg.arg3 = fd_table[fd].position;
    msg.ptr1 = buf;
    msg.ptr2 = (void *)(intptr_t)size;

    rep = do_request(&msg);
    if (rep.retval == ERROR) return ERROR;

    fd_table[fd].position = rep.newpos;
    return rep.retval; /* bytes written */
}

/* -----------------------------------------------------------------------
 * Seek
 * ----------------------------------------------------------------------- */
int
Seek(int fd, int offset, int whence)
{
    struct yfs_msg msg;
    struct yfs_reply rep;

    lib_init();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_open)
        return ERROR;

    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_SEEK;
    msg.arg1 = fd_table[fd].inum;
    msg.arg2 = fd_table[fd].reuse;
    msg.arg3 = fd_table[fd].position;
    msg.ptr1 = (void *)(intptr_t)offset;
    msg.ptr2 = (void *)(intptr_t)whence;

    rep = do_request(&msg);
    if (rep.retval == ERROR) return ERROR;

    fd_table[fd].position = rep.retval;
    return rep.retval;
}

/* -----------------------------------------------------------------------
 * Link
 * ----------------------------------------------------------------------- */
int
Link(char *oldname, char *newname)
{
    struct yfs_msg msg;
    struct yfs_reply rep;

    lib_init();
    if (oldname == NULL || newname == NULL) return ERROR;

    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_LINK;
    msg.arg1 = cwd_inum;
    msg.arg2 = (int)strlen(oldname) + 1;
    msg.arg3 = (int)strlen(newname) + 1;
    msg.ptr1 = oldname;
    msg.ptr2 = newname;

    rep = do_request(&msg);
    return rep.retval;
}

/* -----------------------------------------------------------------------
 * Unlink
 * ----------------------------------------------------------------------- */
int
Unlink(char *pathname)
{
    struct yfs_msg msg;
    struct yfs_reply rep;

    lib_init();
    if (pathname == NULL) return ERROR;

    memset(&msg, 0, sizeof(msg));
    msg.type = MSG_UNLINK;
