/*
 * yfs.c - Yalnix File System Server
 *
 * Implements:
 *   - LRU write-back block cache (BLOCK_CACHESIZE entries)
 *   - LRU write-back inode cache (INODE_CACHESIZE entries)
 *   - Free block and inode lists (built at startup from disk scan)
 *   - All file system operations: open, create, read, write, seek,
 *     link, unlink, symlink, readlink, mkdir, rmdir, chdir, stat,
 *     sync, shutdown
 */

#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#include <comp421/yalnix.h>
#include <comp421/iolib.h>
#include <comp421/filesystem.h>

#include "yfs_msg.h"

/* =========================================================================
 * Constants derived from filesystem.h
 * ========================================================================= */

#define INODES_PER_BLOCK  (BLOCKSIZE / INODESIZE)    /* 8 */
#define ENTRIES_PER_BLOCK (BLOCKSIZE / sizeof(struct dir_entry))  /* 16 */
#define PTRS_PER_BLOCK    (BLOCKSIZE / sizeof(int))  /* 128 */

/* =========================================================================
 * Block Cache
 * ========================================================================= */

#define BCACHE_HASH  64   /* hash table size for block cache */

struct bcache_entry {
    int  blocknum;                /* disk block number; 0 = unused slot */
    int  dirty;
    struct bcache_entry *hash_next;
    struct bcache_entry *lru_prev;
    struct bcache_entry *lru_next;
    char data[BLOCKSIZE];
};

static struct bcache_entry  bcache[BLOCK_CACHESIZE];
static struct bcache_entry *bhash[BCACHE_HASH];
static struct bcache_entry *blru_head; /* MRU end */
static struct bcache_entry *blru_tail; /* LRU end (evict here) */
static int    bcache_used;            /* filled slots */

/* LRU list helpers */
static void
blru_remove(struct bcache_entry *e)
{
    if (e->lru_prev) e->lru_prev->lru_next = e->lru_next;
    else              blru_head = e->lru_next;
    if (e->lru_next) e->lru_next->lru_prev = e->lru_prev;
    else              blru_tail = e->lru_prev;
    e->lru_prev = e->lru_next = NULL;
}

static void
blru_push_head(struct bcache_entry *e)
{
    e->lru_next = blru_head;
    e->lru_prev = NULL;
    if (blru_head) blru_head->lru_prev = e;
    blru_head = e;
    if (!blru_tail) blru_tail = e;
}

static void
blru_touch(struct bcache_entry *e)
{
    blru_remove(e);
    blru_push_head(e);
}

/* Write a block cache entry to disk */
static void
bflush(struct bcache_entry *e)
{
    if (e->dirty) {
        WriteSector(e->blocknum, e->data);
        e->dirty = 0;
    }
}

/* Remove from hash chain */
static void
bhash_remove(struct bcache_entry *e)
{
    int h = e->blocknum % BCACHE_HASH;
    struct bcache_entry **pp = &bhash[h];
    while (*pp && *pp != e) pp = &(*pp)->hash_next;
    if (*pp) *pp = e->hash_next;
    e->hash_next = NULL;
}

/* Look up a block in the cache; returns entry or NULL */
static struct bcache_entry *
bcache_lookup(int blocknum)
{
    int h = blocknum % BCACHE_HASH;
    struct bcache_entry *e = bhash[h];
    while (e) {
        if (e->blocknum == blocknum) return e;
        e = e->hash_next;
    }
    return NULL;
}

/*
 * Get or load a block into the cache. Returns pointer to the 512-byte data.
 * Never returns NULL (fatal if disk read fails).
 */
static char *
get_block(int blocknum)
{
    struct bcache_entry *e;
    int h;

    e = bcache_lookup(blocknum);
    if (e) {
        blru_touch(e);
        return e->data;
    }

    /* Need a slot */
    if (bcache_used < BLOCK_CACHESIZE) {
        /* find an unused slot */
        int i;
        for (i = 0; i < BLOCK_CACHESIZE; i++) {
            if (bcache[i].blocknum == 0) {
                e = &bcache[i];
                break;
            }
        }
        bcache_used++;
    } else {
        /* evict LRU */
        e = blru_tail;
        bflush(e);
        bhash_remove(e);
        blru_remove(e);
    }

    /* Load from disk */
    e->blocknum   = blocknum;
    e->dirty      = 0;
    e->hash_next  = NULL;
    e->lru_prev   = NULL;
    e->lru_next   = NULL;
    ReadSector(blocknum, e->data);

    h = blocknum % BCACHE_HASH;
    e->hash_next = bhash[h];
    bhash[h] = e;
    blru_push_head(e);
    return e->data;
}

/* Mark a cached block as dirty */
static void
mark_block_dirty(int blocknum)
{
    struct bcache_entry *e = bcache_lookup(blocknum);
    if (e) e->dirty = 1;
}

/* Sync: flush all dirty blocks */
static void
sync_blocks(void)
{
    int i;
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        if (bcache[i].blocknum != 0)
            bflush(&bcache[i]);
    }
}

/* =========================================================================
 * Inode Cache
 * ========================================================================= */

#define ICACHE_HASH  32

struct icache_entry {
    int  inum;
    int  dirty;
    struct icache_entry *hash_next;
    struct icache_entry *lru_prev;
    struct icache_entry *lru_next;
    struct inode inode;
};

static struct icache_entry  icache[INODE_CACHESIZE];
static struct icache_entry *ihash[ICACHE_HASH];
static struct icache_entry *ilru_head;
static struct icache_entry *ilru_tail;
static int    icache_used;

static void
ilru_remove(struct icache_entry *e)
{
    if (e->lru_prev) e->lru_prev->lru_next = e->lru_next;
    else              ilru_head = e->lru_next;
    if (e->lru_next) e->lru_next->lru_prev = e->lru_prev;
    else              ilru_tail = e->lru_prev;
    e->lru_prev = e->lru_next = NULL;
}

static void
ilru_push_head(struct icache_entry *e)
{
    e->lru_next = ilru_head;
    e->lru_prev = NULL;
    if (ilru_head) ilru_head->lru_prev = e;
    ilru_head = e;
    if (!ilru_tail) ilru_tail = e;
}

static void
ilru_touch(struct icache_entry *e)
{
    ilru_remove(e);
    ilru_push_head(e);
}

/* Returns disk block number containing inode inum */
static int
inode_block(int inum)
{
    return 1 + inum / INODES_PER_BLOCK;
}

/* Returns byte offset within block for inode inum */
static int
inode_offset(int inum)
{
    return (inum % INODES_PER_BLOCK) * INODESIZE;
}

/* Write an inode back through the block cache */
static void
iflush(struct icache_entry *e)
{
    if (e->dirty) {
        int blk = inode_block(e->inum);
        int off = inode_offset(e->inum);
        char *bdata = get_block(blk);
        memcpy(bdata + off, &e->inode, INODESIZE);
        mark_block_dirty(blk);
        e->dirty = 0;
    }
}

static void
ihash_remove(struct icache_entry *e)
{
    int h = e->inum % ICACHE_HASH;
    struct icache_entry **pp = &ihash[h];
    while (*pp && *pp != e) pp = &(*pp)->hash_next;
    if (*pp) *pp = e->hash_next;
    e->hash_next = NULL;
}

static struct icache_entry *
icache_lookup(int inum)
{
    int h = inum % ICACHE_HASH;
    struct icache_entry *e = ihash[h];
    while (e) {
        if (e->inum == inum) return e;
        e = e->hash_next;
    }
    return NULL;
}

/*
 * Get a pointer to the inode for 'inum'. The inode is loaded from the
 * block cache (and block cache from disk if needed). Returns NULL on error.
 */
static struct inode *
get_inode(int inum)
{
    struct icache_entry *e;
    int blk, off, h;
    char *bdata;

    e = icache_lookup(inum);
    if (e) {
        ilru_touch(e);
        return &e->inode;
    }

    /* Need a slot */
    if (icache_used < INODE_CACHESIZE) {
        int i;
        for (i = 0; i < INODE_CACHESIZE; i++) {
            if (icache[i].inum == 0) {
                e = &icache[i];
                break;
            }
        }
        icache_used++;
    } else {
        e = ilru_tail;
        iflush(e);
        ihash_remove(e);
        ilru_remove(e);
    }

    blk   = inode_block(inum);
    off   = inode_offset(inum);
    bdata = get_block(blk);
    memcpy(&e->inode, bdata + off, INODESIZE);

    e->inum      = inum;
    e->dirty     = 0;
    e->hash_next = NULL;
    e->lru_prev  = NULL;
    e->lru_next  = NULL;

    h = inum % ICACHE_HASH;
    e->hash_next = ihash[h];
    ihash[h] = e;
    ilru_push_head(e);

    return &e->inode;
}

/* Mark inode as dirty */
static void
mark_inode_dirty(int inum)
{
    struct icache_entry *e = icache_lookup(inum);
    if (e) e->dirty = 1;
}

/* Sync: flush all dirty inodes then all dirty blocks */
static void
sync_inodes(void)
{
    int i;
    for (i = 0; i < INODE_CACHESIZE; i++) {
        if (icache[i].inum != 0)
            iflush(&icache[i]);
    }
}

/* =========================================================================
 * Free block and inode lists
 * ========================================================================= */

static int *free_blocks;    /* stack of free block numbers */
static int  free_block_cnt;
static int *free_inodes;    /* stack of free inode numbers */
static int  free_inode_cnt;
static int  num_blocks;     /* from fs_header */
static int  num_inodes;     /* from fs_header */
static int  first_data_blk; /* first data block number */

static void
push_free_block(int blk)
{
    free_blocks[free_block_cnt++] = blk;
}

static int
pop_free_block(void)
{
    if (free_block_cnt == 0) return 0; /* 0 = none available */
    return free_blocks[--free_block_cnt];
}

static void
push_free_inode(int inum)
{
    free_inodes[free_inode_cnt++] = inum;
}

static int
pop_free_inode(void)
{
    if (free_inode_cnt == 0) return 0;
    return free_inodes[--free_inode_cnt];
}

/* Allocate a new block (returns block number or 0 on failure) */
static int
alloc_block(void)
{
    int blk = pop_free_block();
    if (blk == 0) return 0;
    /* zero-fill the new block */
    char *data = get_block(blk);
    memset(data, 0, BLOCKSIZE);
    mark_block_dirty(blk);
    return blk;
}

/* Return a block to the free list */
static void
release_block(int blk)
{
    if (blk == 0) return;
    push_free_block(blk);
    /* zero it in cache if present */
    struct bcache_entry *e = bcache_lookup(blk);
    if (e) {
        memset(e->data, 0, BLOCKSIZE);
        e->dirty = 0;
        e->blocknum = 0; /* invalidate cache entry */
        bhash_remove(e);
        blru_remove(e);
        bcache_used--;
    }
}

/* Allocate a new inode (returns inum or 0 on failure) */
static int
alloc_inode(void)
{
    int inum = pop_free_inode();
    if (inum == 0) return 0;
    struct inode *ip = get_inode(inum);
    ip->reuse++;
    ip->type   = INODE_FREE; /* caller sets type */
    ip->nlink  = 0;
    ip->size   = 0;
    memset(ip->direct, 0, sizeof(ip->direct));
    ip->indirect = 0;
    mark_inode_dirty(inum);
    return inum;
}

/* Return an inode to the free list */
static void
release_inode(int inum)
{
    struct inode *ip = get_inode(inum);
    ip->type  = INODE_FREE;
    ip->nlink = 0;
    ip->size  = 0;
    memset(ip->direct, 0, sizeof(ip->direct));
    ip->indirect = 0;
    mark_inode_dirty(inum);
    push_free_inode(inum);
}

/* =========================================================================
 * Initialization: build free lists from disk
 * ========================================================================= */

/*
 * Mark all blocks used by inode 'inum' as in-use in the bitmap.
 * used_bitmap[blk] = 1 means block is in use.
 */
static void
mark_inode_blocks_used(int inum, char *used_bitmap)
{
    struct inode *ip = get_inode(inum);
    int i;

    for (i = 0; i < NUM_DIRECT; i++) {
        if (ip->direct[i] > 0)
            used_bitmap[ip->direct[i]] = 1;
    }
    if (ip->indirect > 0) {
        used_bitmap[ip->indirect] = 1;
        int *ptrs = (int *)get_block(ip->indirect);
        for (i = 0; i < PTRS_PER_BLOCK; i++) {
            if (ptrs[i] > 0)
                used_bitmap[ptrs[i]] = 1;
        }
    }
}

static void
fs_init(void)
{
    int i;
    char *used_bitmap;
    struct fs_header *hdr;
    char *blk1;

    /* Read superblock (block 1) */
    blk1 = get_block(1);
    hdr  = (struct fs_header *)blk1;
    num_blocks  = hdr->num_blocks;
    num_inodes  = hdr->num_inodes;

    /* First data block */
    first_data_blk = 1 + (num_inodes + 1 + INODES_PER_BLOCK - 1)
                           / INODES_PER_BLOCK;

    TracePrintf(0, "YFS: num_blocks=%d num_inodes=%d first_data_blk=%d\n",
                num_blocks, num_inodes, first_data_blk);

    /* Allocate arrays */
    free_blocks = (int *)malloc(num_blocks * sizeof(int));
    free_inodes = (int *)malloc((num_inodes + 1) * sizeof(int));
    used_bitmap = (char *)malloc(num_blocks);
    memset(used_bitmap, 0, num_blocks);
    free_block_cnt = 0;
    free_inode_cnt = 0;

    /* Mark inode-region blocks as used */
    for (i = 1; i < first_data_blk; i++)
        used_bitmap[i] = 1;

    /* Scan inodes: build free inode list + mark data blocks in use */
    for (i = 1; i <= num_inodes; i++) {
        struct inode *ip = get_inode(i);
        if (ip->type == INODE_FREE) {
            push_free_inode(i);
        } else {
            mark_inode_blocks_used(i, used_bitmap);
        }
    }

    /* Build free block list */
    for (i = first_data_blk; i < num_blocks; i++) {
        if (!used_bitmap[i])
            push_free_block(i);
    }

    free(used_bitmap);
    TracePrintf(0, "YFS: free_blocks=%d free_inodes=%d\n",
                free_block_cnt, free_inode_cnt);
}

/* =========================================================================
 * Block access helpers for file data
 * ========================================================================= */

/*
 * Returns the disk block number for logical block index 'idx' in the file
 * described by inode 'ip'. Returns 0 for a hole (unallocated block).
 */
static int
get_file_blocknum(struct inode *ip, int idx)
{
    if (idx < NUM_DIRECT) {
        return ip->direct[idx];
    }
    idx -= NUM_DIRECT;
    if (ip->indirect == 0) return 0;
    int *ptrs = (int *)get_block(ip->indirect);
    if (idx >= PTRS_PER_BLOCK) return 0;
    return ptrs[idx];
}

/*
 * Allocate or return the block for logical index 'idx' in inode 'ip' (inum).
 * Allocates new blocks as needed. Returns block number, or 0 on failure.
 */
static int
get_or_alloc_file_block(int inum, struct inode *ip, int idx)
{
    if (idx < NUM_DIRECT) {
        if (ip->direct[idx] == 0) {
            int blk = alloc_block();
            if (blk == 0) return 0;
            ip->direct[idx] = blk;
            mark_inode_dirty(inum);
        }
        return ip->direct[idx];
    }
    idx -= NUM_DIRECT;
    if (idx >= PTRS_PER_BLOCK) return 0;
    if (ip->indirect == 0) {
        int iblk = alloc_block();
        if (iblk == 0) return 0;
        ip->indirect = iblk;
        mark_inode_dirty(inum);
    }
    int *ptrs = (int *)get_block(ip->indirect);
    if (ptrs[idx] == 0) {
        int blk = alloc_block();
        if (blk == 0) return 0;
        ptrs[idx] = blk;
        mark_block_dirty(ip->indirect);
    }
    return ptrs[idx];
}

/* Free all data blocks of an inode (direct + indirect) */
static void
free_inode_blocks(struct inode *ip)
{
    int i;
    for (i = 0; i < NUM_DIRECT; i++) {
        if (ip->direct[i]) {
            release_block(ip->direct[i]);
            ip->direct[i] = 0;
        }
    }
    if (ip->indirect) {
        int *ptrs = (int *)get_block(ip->indirect);
        for (i = 0; i < PTRS_PER_BLOCK; i++) {
            if (ptrs[i]) {
                release_block(ptrs[i]);
                ptrs[i] = 0;
            }
        }
        release_block(ip->indirect);
        ip->indirect = 0;
    }
}

/* =========================================================================
 * Directory helpers
 * ========================================================================= */

/*
 * Look up 'name' (up to namelen chars, or null-terminated) in directory inum.
 * Returns the child inum, or 0 if not found.
 */
static int
dir_lookup(int dir_inum, const char *name, int namelen)
{
    struct inode *dir_ip = get_inode(dir_inum);
    int total = dir_ip->size;
    int pos = 0;

    /* namelen <= 0 means null-terminated */
    if (namelen <= 0) namelen = (int)strlen(name);
    if (namelen > DIRNAMELEN) return 0;

    while (pos < total) {
        int bidx = pos / BLOCKSIZE;
        int off  = pos % BLOCKSIZE;
        int blk  = get_file_blocknum(dir_ip, bidx);

        /* If no block (hole) - shouldn't happen in dirs but handle it */
        if (blk == 0) {
            pos += BLOCKSIZE - off;
            continue;
        }
        char *bdata = get_block(blk);
        while (off + (int)sizeof(struct dir_entry) <= BLOCKSIZE
               && pos < total) {
            struct dir_entry *de = (struct dir_entry *)(bdata + off);
            if (de->inum != 0) {
                /* Compare name up to DIRNAMELEN chars */
                int match = 1;
                int i;
                for (i = 0; i < namelen; i++) {
                    if (i >= DIRNAMELEN || de->name[i] != name[i]) {
                        match = 0; break;
                    }
                }
                /* also ensure de->name ends at or after namelen */
                if (match && namelen < DIRNAMELEN
                    && de->name[namelen] != '\0')
                    match = 0;
                if (match) return de->inum;
            }
            off += sizeof(struct dir_entry);
            pos += sizeof(struct dir_entry);
        }
        /* If block not fully consumed, skip to next block */
        if (off < BLOCKSIZE && pos < total) {
            int skip = BLOCKSIZE - off;
            pos += skip;
        }
    }
    return 0;
}

/*
 * Add a directory entry for (name, child_inum) into directory dir_inum.
 * Reuses a free slot (inum==0) if available, else appends.
 * Returns 0 on success, ERROR on failure.
 */
static int
dir_add(int dir_inum, const char *name, int namelen, int child_inum)
{
    struct inode *dir_ip = get_inode(dir_inum);
    int total = dir_ip->size;
    int pos = 0;

    if (namelen <= 0) namelen = (int)strlen(name);
    if (namelen > DIRNAMELEN) return ERROR;

    /* Search for a free slot */
    while (pos < total) {
        int bidx = pos / BLOCKSIZE;
        int off  = pos % BLOCKSIZE;
        int blk  = get_file_blocknum(dir_ip, bidx);
        if (blk == 0) { pos += BLOCKSIZE - off; continue; }
        char *bdata = get_block(blk);
        while (off + (int)sizeof(struct dir_entry) <= BLOCKSIZE
               && pos < total) {
            struct dir_entry *de = (struct dir_entry *)(bdata + off);
            if (de->inum == 0) {
                /* Reuse this free slot */
                memset(de, 0, sizeof(struct dir_entry));
                de->inum = (short)child_inum;
                memcpy(de->name, name, namelen);
                mark_block_dirty(blk);
                return 0;
            }
            off += sizeof(struct dir_entry);
            pos += sizeof(struct dir_entry);
        }
        if (off < BLOCKSIZE && pos < total) pos += BLOCKSIZE - off;
    }

    /* Append a new entry */
    int bidx = total / BLOCKSIZE;
    int off  = total % BLOCKSIZE;
    int blk  = get_or_alloc_file_block(dir_inum, dir_ip, bidx);
    if (blk == 0) return ERROR;
    char *bdata = get_block(blk);
    struct dir_entry *de = (struct dir_entry *)(bdata + off);
    memset(de, 0, sizeof(struct dir_entry));
    de->inum = (short)child_inum;
    memcpy(de->name, name, namelen);
    mark_block_dirty(blk);
    dir_ip->size += sizeof(struct dir_entry);
    mark_inode_dirty(dir_inum);
    return 0;
}

/*
 * Remove (set inum=0) a directory entry with the given name from dir_inum.
 * Returns 0 on success, ERROR if not found.
 */
static int
dir_remove(int dir_inum, const char *name, int namelen)
{
    struct inode *dir_ip = get_inode(dir_inum);
    int total = dir_ip->size;
    int pos = 0;

    if (namelen <= 0) namelen = (int)strlen(name);
    if (namelen > DIRNAMELEN) return ERROR;

    while (pos < total) {
        int bidx = pos / BLOCKSIZE;
        int off  = pos % BLOCKSIZE;
        int blk  = get_file_blocknum(dir_ip, bidx);
        if (blk == 0) { pos += BLOCKSIZE - off; continue; }
        char *bdata = get_block(blk);
        while (off + (int)sizeof(struct dir_entry) <= BLOCKSIZE
               && pos < total) {
            struct dir_entry *de = (struct dir_entry *)(bdata + off);
            if (de->inum != 0) {
                int match = 1, i;
                for (i = 0; i < namelen; i++) {
                    if (i >= DIRNAMELEN || de->name[i] != name[i]) {
                        match = 0; break;
                    }
                }
                if (match && namelen < DIRNAMELEN
                    && de->name[namelen] != '\0')
                    match = 0;
                if (match) {
                    de->inum = 0;
                    memset(de->name, 0, DIRNAMELEN);
                    mark_block_dirty(blk);
                    return 0;
                }
            }
            off += sizeof(struct dir_entry);
            pos += sizeof(struct dir_entry);
        }
        if (off < BLOCKSIZE && pos < total) pos += BLOCKSIZE - off;
    }
    return ERROR;
}

/* =========================================================================
 * Path resolution (namei)
 * ========================================================================= */

/*
 * Parse next path component from *path into component[].
 * Advances *path past the component and any following slashes.
 * Returns length of component (0 = done, end of path).
 */
static int
next_component(const char **path, char *component)
{
    /* skip leading slashes */
    while (**path == '/') (*path)++;
    if (**path == '\0') return 0;

    int len = 0;
    while (**path != '/' && **path != '\0') {
        if (len < DIRNAMELEN)
            component[len] = **path;
        len++;
        (*path)++;
    }
    if (len < DIRNAMELEN) component[len] = '\0';
    else component[DIRNAMELEN] = '\0';

    /* Skip trailing slashes — if there are trailing slashes, treat as "." */
    /* Note: we handle trailing slash in namei by detecting empty component */
    return len;
}

#define NAMEI_LOOKUP   0  /* don't follow last symlink (for unlink, link, readlink) */
#define NAMEI_FOLLOW   1  /* follow last symlink (open, create, chdir, stat) */

/*
 * Resolve a path to an inode number.
 *
 *   cwd:        inode of current working directory
 *   path:       the pathname to resolve
 *   parent_out: if non-NULL, receives the parent directory inode
 *   last_name:  if non-NULL, receives the last path component name
 *   last_namelen: receives length of last_name
 *   follow:     NAMEI_FOLLOW or NAMEI_LOOKUP for final component symlink
 *   depth:      symlink recursion depth (caller passes 0)
 *
 * Returns inode number on success, or 0 on "not found",
 * or ERROR (-1) on hard error.
 */
static int
namei(int cwd, const char *path, int *parent_out,
      char *last_name, int *last_namelen,
      int follow, int depth)
{
    int cur_inum;
    char component[DIRNAMELEN + 1];
    const char *p = path;
    int child_inum;
    int prev_inum;

    if (path == NULL || path[0] == '\0') return ERROR;
    if (depth > MAXSYMLINKS) return ERROR;

    /* Start from root or cwd */
    if (path[0] == '/') {
        cur_inum = ROOTINODE;
        /* skip leading slashes */
        while (*p == '/') p++;
        if (*p == '\0') {
            /* path is just "/" or "//..." */
            if (parent_out) *parent_out = ROOTINODE;
            if (last_name) { last_name[0] = '.'; last_name[1] = '\0'; }
            if (last_namelen) *last_namelen = 1;
            if (follow == NAMEI_FOLLOW) return ROOTINODE;
            return ROOTINODE;
        }
    } else {
        cur_inum = cwd;
    }

    prev_inum = cur_inum;

    for (;;) {
        int len = next_component(&p, component);

        if (len == 0) {
            /* Trailing slash was handled as "." */
            /* cur_inum is the result */
            if (parent_out) *parent_out = prev_inum;
            if (last_name) { memcpy(last_name, ".", 2); }
            if (last_namelen) *last_namelen = 1;
            return cur_inum;
        }

        if (len > DIRNAMELEN) return ERROR; /* name too long */

        /* Is there a next component? */
        const char *save = p;
        char tmp[DIRNAMELEN + 1];
        int has_more = (next_component(&save, tmp) > 0);

        /* Make sure cur_inum is a directory */
        struct inode *ip = get_inode(cur_inum);
        if (ip == NULL) return ERROR;
        if (ip->type != INODE_DIRECTORY) return ERROR;

        /* Look up component in cur directory */
        prev_inum = cur_inum;
        child_inum = dir_lookup(cur_inum, component, len);

        /* If last component not found */
        if (child_inum == 0) {
            if (!has_more) {
                /* Return "not found" with parent info */
                if (parent_out) *parent_out = prev_inum;
                if (last_name) { memcpy(last_name, component, len + 1); }
                if (last_namelen) *last_namelen = len;
                return 0; /* not found */
            }
            return ERROR; /* intermediate component not found */
        }

        /* Check if it's a symlink */
        struct inode *cip = get_inode(child_inum);
        if (cip == NULL) return ERROR;

        int is_last = !has_more;
        if (cip->type == INODE_SYMLINK && (has_more || follow == NAMEI_FOLLOW)) {
            /* Follow symlink */
            if (depth >= MAXSYMLINKS) return ERROR;

            /* Read symlink target */
            int slen = cip->size;
            if (slen <= 0 || slen >= MAXPATHNAMELEN) return ERROR;
            char *sbuf = (char *)malloc(slen + 1);
            if (!sbuf) return ERROR;

            /* Read symlink data */
            int idx = 0, spos = 0;
            while (spos < slen) {
                int sidx = spos / BLOCKSIZE;
                int soff = spos % BLOCKSIZE;
                int sblk = get_file_blocknum(cip, sidx);
                if (sblk == 0) { free(sbuf); return ERROR; }
                char *sd = get_block(sblk);
                int copy = BLOCKSIZE - soff;
                if (copy > slen - spos) copy = slen - spos;
                memcpy(sbuf + idx, sd + soff, copy);
                idx  += copy;
                spos += copy;
            }
            sbuf[slen] = '\0';

            int new_cwd;
            if (sbuf[0] == '/') {
                new_cwd = ROOTINODE;
            } else {
                new_cwd = prev_inum; /* relative to dir containing symlink */
            }

            /* Build remaining path: symlink_target + "/" + rest-of-path */
            char *newpath;
            if (*p != '\0') {
                int plen = (int)strlen(p);
                newpath = (char *)malloc(slen + 1 + plen + 1);
                if (!newpath) { free(sbuf); return ERROR; }
                memcpy(newpath, sbuf, slen);
                newpath[slen] = '/';
                memcpy(newpath + slen + 1, p, plen + 1);
            } else {
                newpath = sbuf;
                sbuf = NULL;
            }

            int ret = namei(new_cwd, newpath, parent_out, last_name,
                            last_namelen, follow, depth + 1);
            free(newpath);
            if (sbuf) free(sbuf);
            return ret;
        }

        if (is_last) {
            if (parent_out) *parent_out = prev_inum;
            if (last_name) { memcpy(last_name, component, len + 1); }
            if (last_namelen) *last_namelen = len;
            return child_inum;
        }

        cur_inum = child_inum;
    }
}

/* =========================================================================
 * File system operations
 * ========================================================================= */

static struct yfs_reply make_error(void)
{
    struct yfs_reply r;
    memset(&r, 0, sizeof(r));
    r.retval = ERROR;
    return r;
}

static struct yfs_reply make_ok(int retval)
{
    struct yfs_reply r;
    memset(&r, 0, sizeof(r));
    r.retval = retval;
    return r;
}

/* -----------------------------------------------------------------------
 * Open
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_open(int cwd, char *path)
{
    int parent;
    char name[DIRNAMELEN + 1];
    int nlen;
    int inum = namei(cwd, path, &parent, name, &nlen, NAMEI_FOLLOW, 0);
    if (inum <= 0) return make_error();

    struct inode *ip = get_inode(inum);
    if (ip->type == INODE_FREE) return make_error();

    struct yfs_reply r = make_ok(0);
    r.inum  = inum;
    r.reuse = ip->reuse;
    return r;
}

/* -----------------------------------------------------------------------
 * Create
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_create(int cwd, char *path)
{
    int parent;
    char name[DIRNAMELEN + 1];
    int nlen;
    int inum = namei(cwd, path, &parent, name, &nlen, NAMEI_FOLLOW, 0);

    if (inum == ERROR) return make_error();

    if (inum > 0) {
        /* File exists */
        struct inode *ip = get_inode(inum);
        if (ip->type == INODE_DIRECTORY) return make_error();
        /* Truncate existing file */
        free_inode_blocks(ip);
        ip->size = 0;
        mark_inode_dirty(inum);
        struct yfs_reply r = make_ok(0);
        r.inum  = inum;
        r.reuse = ip->reuse;
        return r;
    }

    /* inum == 0: create new file */
    if (parent == 0) return make_error();

    /* Validate name length */
    if (nlen <= 0 || nlen > DIRNAMELEN) return make_error();

    int new_inum = alloc_inode();
    if (new_inum == 0) return make_error();

    struct inode *ip = get_inode(new_inum);
    ip->type  = INODE_REGULAR;
    ip->nlink = 1;
    ip->size  = 0;
    mark_inode_dirty(new_inum);

    if (dir_add(parent, name, nlen, new_inum) == ERROR) {
        ip->type  = INODE_FREE;
        ip->nlink = 0;
        mark_inode_dirty(new_inum);
        push_free_inode(new_inum);
        return make_error();
    }

    struct yfs_reply r = make_ok(0);
    r.inum  = new_inum;
    r.reuse = ip->reuse;
    return r;
}

/* -----------------------------------------------------------------------
 * Read
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_read(int inum, int reuse, int pos, void *client_buf, int size, int sender)
{
    struct inode *ip = get_inode(inum);
    if (ip == NULL || ip->type == INODE_FREE) return make_error();
    if (ip->reuse != reuse) return make_error();
    if (ip->type == INODE_SYMLINK) return make_error();

    if (size < 0) return make_error();
    if (pos < 0) return make_error();

    int avail = ip->size - pos;
    if (avail <= 0) {
        struct yfs_reply r = make_ok(0);
        r.newpos = pos;
        return r;
    }
    if (size > avail) size = avail;

    /* Transfer data block by block using CopyTo */
    int done = 0;
    char tmp[BLOCKSIZE];
    while (done < size) {
        int bidx  = (pos + done) / BLOCKSIZE;
        int boff  = (pos + done) % BLOCKSIZE;
        int chunk = BLOCKSIZE - boff;
        if (chunk > size - done) chunk = size - done;

        int blk = get_file_blocknum(ip, bidx);
        if (blk == 0) {
            /* hole: read zeros */
            memset(tmp, 0, chunk);
        } else {
            char *bdata = get_block(blk);
            memcpy(tmp, bdata + boff, chunk);
        }
        /* Copy chunk to client's buffer */
        if (CopyTo(sender, (char *)client_buf + done, tmp, chunk) != 0)
            return make_error();
        done += chunk;
    }

    struct yfs_reply r = make_ok(done);
    r.newpos = pos + done;
    return r;
}

/* -----------------------------------------------------------------------
 * Write
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_write(int inum, int reuse, int pos, void *client_buf, int size, int sender)
{
    struct inode *ip = get_inode(inum);
    if (ip == NULL || ip->type == INODE_FREE) return make_error();
    if (ip->reuse != reuse) return make_error();
    if (ip->type == INODE_DIRECTORY) return make_error();
    if (ip->type == INODE_SYMLINK) return make_error();

    if (size < 0) return make_error();
    if (pos < 0) return make_error();

    int done = 0;
    char tmp[BLOCKSIZE];
    while (done < size) {
        int bidx  = (pos + done) / BLOCKSIZE;
        int boff  = (pos + done) % BLOCKSIZE;
        int chunk = BLOCKSIZE - boff;
        if (chunk > size - done) chunk = size - done;

        int blk = get_or_alloc_file_block(inum, ip, bidx);
        if (blk == 0) break; /* disk full */

        /* Re-fetch ip since cache may have evicted it during block alloc */
        ip = get_inode(inum);

        char *bdata = get_block(blk);
        /* Read data from client */
        if (CopyFrom(sender, tmp, (char *)client_buf + done, chunk) != 0)
            break;
        memcpy(bdata + boff, tmp, chunk);
        mark_block_dirty(blk);
        done += chunk;
    }

    if (done == 0 && size > 0) return make_error();

    /* Update file size if position advanced beyond current end */
    ip = get_inode(inum);
    if (pos + done > ip->size) {
        ip->size = pos + done;
        mark_inode_dirty(inum);
    }

    struct yfs_reply r = make_ok(done);
    r.newpos = pos + done;
    return r;
}

/* -----------------------------------------------------------------------
 * Seek
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_seek(int inum, int reuse, int cur_pos, int offset, int whence)
{
    struct inode *ip = get_inode(inum);
    if (ip == NULL || ip->type == INODE_FREE) return make_error();
    if (ip->reuse != reuse) return make_error();

    int newpos;
    if (whence == SEEK_SET) {
        newpos = offset;
    } else if (whence == SEEK_CUR) {
        newpos = cur_pos + offset;
    } else if (whence == SEEK_END) {
        newpos = ip->size + offset;
    } else {
        return make_error();
    }

    if (newpos < 0) return make_error();
    return make_ok(newpos);
}

/* -----------------------------------------------------------------------
 * Link
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_link(int cwd, char *oldname, char *newname)
{
    /* Resolve old path - must exist and not be a directory */
    int old_inum = namei(cwd, oldname, NULL, NULL, NULL, NAMEI_LOOKUP, 0);
    if (old_inum <= 0) return make_error();

    struct inode *old_ip = get_inode(old_inum);
    if (old_ip->type == INODE_DIRECTORY) return make_error();
    if (old_ip->type == INODE_FREE) return make_error();

    /* Resolve new path - must NOT exist; parent must exist */
    int new_parent;
    char new_comp[DIRNAMELEN + 1];
    int new_clen;
    int new_inum = namei(cwd, newname, &new_parent, new_comp, &new_clen,
                         NAMEI_LOOKUP, 0);
    if (new_inum != 0) return make_error(); /* already exists */
    if (new_parent == 0) return make_error();
    if (new_clen <= 0 || new_clen > DIRNAMELEN) return make_error();

    /* Add directory entry */
    if (dir_add(new_parent, new_comp, new_clen, old_inum) == ERROR)
        return make_error();

    old_ip = get_inode(old_inum);
    old_ip->nlink++;
    mark_inode_dirty(old_inum);

    return make_ok(0);
}

/* -----------------------------------------------------------------------
 * Unlink
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_unlink(int cwd, char *pathname)
{
    int parent;
    char name[DIRNAMELEN + 1];
    int nlen;
    int inum = namei(cwd, pathname, &parent, name, &nlen, NAMEI_LOOKUP, 0);
    if (inum <= 0) return make_error();

    struct inode *ip = get_inode(inum);
    if (ip->type == INODE_DIRECTORY) return make_error();
    if (ip->type == INODE_FREE) return make_error();

    /* Remove directory entry */
    if (dir_remove(parent, name, nlen) == ERROR) return make_error();

    ip = get_inode(inum);
    ip->nlink--;
    mark_inode_dirty(inum);

    if (ip->nlink <= 0) {
        free_inode_blocks(ip);
        release_inode(inum);
    }

    return make_ok(0);
}

/* -----------------------------------------------------------------------
 * SymLink
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_symlink(int cwd, char *oldname, char *newname)
{
    /* oldname is the target content; newname is where symlink is created */
    /* oldname need not exist; but newname must NOT exist */

    int new_parent;
    char new_comp[DIRNAMELEN + 1];
    int new_clen;
    int new_inum = namei(cwd, newname, &new_parent, new_comp, &new_clen,
                         NAMEI_LOOKUP, 0);
    if (new_inum != 0) return make_error(); /* newname already exists */
    if (new_parent == 0) return make_error();
    if (new_clen <= 0 || new_clen > DIRNAMELEN) return make_error();

    int slen = (int)strlen(oldname);
    if (slen == 0) return make_error(); /* empty target is an error */

    /* Allocate inode for symlink */
    int sl_inum = alloc_inode();
    if (sl_inum == 0) return make_error();

    struct inode *ip = get_inode(sl_inum);
    ip->type  = INODE_SYMLINK;
    ip->nlink = 1;
    ip->size  = 0;
    mark_inode_dirty(sl_inum);

    /* Write symlink target into inode data */
    int written = 0;
    while (written < slen) {
        int bidx  = written / BLOCKSIZE;
        int boff  = written % BLOCKSIZE;
        int chunk = BLOCKSIZE - boff;
        if (chunk > slen - written) chunk = slen - written;

        int blk = get_or_alloc_file_block(sl_inum, ip, bidx);
        if (blk == 0) {
            free_inode_blocks(ip);
            release_inode(sl_inum);
            return make_error();
        }
        ip = get_inode(sl_inum);
        char *bdata = get_block(blk);
        memcpy(bdata + boff, oldname + written, chunk);
        mark_block_dirty(blk);
        written += chunk;
    }
    ip = get_inode(sl_inum);
    ip->size = slen;
    mark_inode_dirty(sl_inum);

    /* Add directory entry for newname */
    if (dir_add(new_parent, new_comp, new_clen, sl_inum) == ERROR) {
        free_inode_blocks(ip);
        release_inode(sl_inum);
        return make_error();
    }

    return make_ok(0);
}

/* -----------------------------------------------------------------------
 * ReadLink
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_readlink(int cwd, char *pathname, char *client_buf, int buflen, int sender)
{
    int inum = namei(cwd, pathname, NULL, NULL, NULL, NAMEI_LOOKUP, 0);
    if (inum <= 0) return make_error();

    struct inode *ip = get_inode(inum);
    if (ip->type != INODE_SYMLINK) return make_error();

    int slen = ip->size;
    int copy  = (slen < buflen) ? slen : buflen;

    int pos = 0;
    while (pos < copy) {
        int bidx  = pos / BLOCKSIZE;
        int boff  = pos % BLOCKSIZE;
        int chunk = BLOCKSIZE - boff;
        if (chunk > copy - pos) chunk = copy - pos;
        int blk = get_file_blocknum(ip, bidx);
        if (blk == 0) return make_error();
        char *bdata = get_block(blk);
        if (CopyTo(sender, client_buf + pos, bdata + boff, chunk) != 0)
            return make_error();
        pos += chunk;
    }

    return make_ok(slen); /* return full symlink length, even if truncated */
}

/* -----------------------------------------------------------------------
 * MkDir
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_mkdir(int cwd, char *pathname)
{
    int parent;
    char name[DIRNAMELEN + 1];
    int nlen;
    int inum = namei(cwd, pathname, &parent, name, &nlen, NAMEI_FOLLOW, 0);
    if (inum != 0) return make_error(); /* already exists */
    if (parent == 0) return make_error();
    if (nlen <= 0 || nlen > DIRNAMELEN) return make_error();

    int new_inum = alloc_inode();
    if (new_inum == 0) return make_error();

    struct inode *ip = get_inode(new_inum);
    ip->type  = INODE_DIRECTORY;
    ip->nlink = 2; /* "." + parent entry */
    ip->size  = 0;
    mark_inode_dirty(new_inum);

    /* Add "." and ".." entries */
    if (dir_add(new_inum, ".", 1, new_inum) == ERROR
        || dir_add(new_inum, "..", 2, parent) == ERROR) {
        free_inode_blocks(get_inode(new_inum));
        release_inode(new_inum);
        return make_error();
    }

    /* Add entry in parent directory */
    if (dir_add(parent, name, nlen, new_inum) == ERROR) {
        free_inode_blocks(get_inode(new_inum));
        release_inode(new_inum);
        return make_error();
    }

    /* Increment parent nlink (new dir's ".." points to parent) */
    struct inode *par_ip = get_inode(parent);
    par_ip->nlink++;
    mark_inode_dirty(parent);

    return make_ok(0);
}

/* -----------------------------------------------------------------------
 * RmDir
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_rmdir(int cwd, char *pathname)
{
    int parent;
    char name[DIRNAMELEN + 1];
    int nlen;
    int inum = namei(cwd, pathname, &parent, name, &nlen, NAMEI_FOLLOW, 0);
    if (inum <= 0) return make_error();
    if (inum == ROOTINODE) return make_error(); /* can't remove root */

    struct inode *ip = get_inode(inum);
    if (ip->type != INODE_DIRECTORY) return make_error();

    /* Verify directory is empty (only "." and ".." are valid non-free entries) */
    int total = ip->size;
    int pos = 0;
    while (pos < total) {
        int bidx = pos / BLOCKSIZE;
        int off  = pos % BLOCKSIZE;
        int blk  = get_file_blocknum(ip, bidx);
        if (blk == 0) { pos += BLOCKSIZE - off; continue; }
        char *bdata = get_block(blk);
        while (off + (int)sizeof(struct dir_entry) <= BLOCKSIZE && pos < total) {
            struct dir_entry *de = (struct dir_entry *)(bdata + off);
            if (de->inum != 0) {
                /* Check if it's "." or ".." */
                int is_dot = (de->name[0] == '.' && de->name[1] == '\0');
                int is_dotdot = (de->name[0] == '.' && de->name[1] == '.'
                                 && de->name[2] == '\0');
                if (!is_dot && !is_dotdot)
                    return make_error(); /* non-empty */
            }
            off += sizeof(struct dir_entry);
            pos += sizeof(struct dir_entry);
        }
        if (off < BLOCKSIZE && pos < total) pos += BLOCKSIZE - off;
    }

    /* Remove entry from parent */
    if (dir_remove(parent, name, nlen) == ERROR) return make_error();

    /* Decrement parent nlink */
    struct inode *par_ip = get_inode(parent);
    par_ip->nlink--;
    mark_inode_dirty(parent);

    /* Free directory blocks and inode */
    ip = get_inode(inum);
    free_inode_blocks(ip);
    release_inode(inum);

    return make_ok(0);
}

/* -----------------------------------------------------------------------
 * ChDir
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_chdir(int cwd, char *pathname)
{
    int inum = namei(cwd, pathname, NULL, NULL, NULL, NAMEI_FOLLOW, 0);
    if (inum <= 0) return make_error();

    struct inode *ip = get_inode(inum);
    if (ip->type != INODE_DIRECTORY) return make_error();

    struct yfs_reply r = make_ok(0);
    r.inum = inum; /* library updates its cwd */
    return r;
}

/* -----------------------------------------------------------------------
 * Stat
 * ----------------------------------------------------------------------- */
static struct yfs_reply
do_stat(int cwd, char *pathname, void *client_statbuf, int sender)
{
    int inum = namei(cwd, pathname, NULL, NULL, NULL, NAMEI_FOLLOW, 0);
    if (inum <= 0) return make_error();

    struct inode *ip = get_inode(inum);
    if (ip->type == INODE_FREE) return make_error();

    struct Stat sb;
    sb.inum  = inum;
    sb.type  = ip->type;
    sb.size  = ip->size;
    sb.nlink = ip->nlink;

    if (CopyTo(sender, client_statbuf, &sb, sizeof(sb)) != 0)
        return make_error();

    return make_ok(0);
}

/* -----------------------------------------------------------------------
 * Sync / Shutdown
 * ----------------------------------------------------------------------- */
static void
do_sync(void)
{
    sync_inodes();
    sync_blocks();
}

/* =========================================================================
 * Main
 * ========================================================================= */

int
main(int argc, char *argv[])
{
    int pid;

    /* Initialize filesystem */
    fs_init();

    /* Register as file server */
    if (Register(FILE_SERVER) != 0) {
        TracePrintf(0, "YFS: Register failed\n");
        Exit(1);
    }

    /* Fork and exec the first client process */
    if (argc > 1) {
        pid = Fork();
        if (pid == 0) {
            Exec(argv[1], argv + 1);
            Exit(1); /* Exec should not return */
        }
    }

    /* Main server loop */
    struct yfs_msg msg;
    while (1) {
        int sender = Receive(&msg);

        if (sender == 0) {
            /* Deadlock break: no more clients */
            break;
        }
        if (sender == ERROR) continue;

        struct yfs_reply reply;
        memset(&reply, 0, sizeof(reply));

        /* Read pathname if needed (into local buffer) */
        char path1[MAXPATHNAMELEN];
        char path2[MAXPATHNAMELEN];
        memset(path1, 0, sizeof(path1));
        memset(path2, 0, sizeof(path2));

        int cwd   = msg.arg1;
        int nlen1 = msg.arg2;
        int nlen2 = msg.arg3;

        /* For path operations, copy pathname from client */
        switch (msg.type) {
        case MSG_OPEN:
        case MSG_CREATE:
        case MSG_MKDIR:
        case MSG_RMDIR:
        case MSG_CHDIR:
        case MSG_UNLINK:
        case MSG_STAT:
            if (nlen1 > 0 && nlen1 <= MAXPATHNAMELEN)
                CopyFrom(sender, path1, msg.ptr1, nlen1);
            path1[nlen1 < MAXPATHNAMELEN ? nlen1 : MAXPATHNAMELEN - 1] = '\0';
            break;
        case MSG_LINK:
        case MSG_SYMLINK:
            if (nlen1 > 0 && nlen1 <= MAXPATHNAMELEN)
                CopyFrom(sender, path1, msg.ptr1, nlen1);
            path1[nlen1 < MAXPATHNAMELEN ? nlen1 : MAXPATHNAMELEN - 1] = '\0';
            if (nlen2 > 0 && nlen2 <= MAXPATHNAMELEN)
                CopyFrom(sender, path2, msg.ptr2, nlen2);
            path2[nlen2 < MAXPATHNAMELEN ? nlen2 : MAXPATHNAMELEN - 1] = '\0';
            break;
        case MSG_READLINK:
            if (nlen1 > 0 && nlen1 <= MAXPATHNAMELEN)
                CopyFrom(sender, path1, msg.ptr1, nlen1);
            path1[nlen1 < MAXPATHNAMELEN ? nlen1 : MAXPATHNAMELEN - 1] = '\0';
            break;
        default:
            break;
        }

        switch (msg.type) {
        case MSG_OPEN:
            reply = do_open(cwd, path1);
            break;
        case MSG_CREATE:
            reply = do_create(cwd, path1);
            break;
        case MSG_READ:
            reply = do_read(msg.arg1, msg.arg2, msg.arg3,
                            msg.ptr1, (int)(intptr_t)msg.ptr2, sender);
            break;
        case MSG_WRITE:
            reply = do_write(msg.arg1, msg.arg2, msg.arg3,
                             msg.ptr1, (int)(intptr_t)msg.ptr2, sender);
            break;
        case MSG_SEEK:
            reply = do_seek(msg.arg1, msg.arg2, msg.arg3,
                            (int)(intptr_t)msg.ptr1,
                            (int)(intptr_t)msg.ptr2);
            break;
        case MSG_LINK:
            reply = do_link(cwd, path1, path2);
            break;
        case MSG_UNLINK:
            reply = do_unlink(cwd, path1);
            break;
        case MSG_SYMLINK:
            reply = do_symlink(cwd, path1, path2);
            break;
        case MSG_READLINK:
            reply = do_readlink(cwd, path1, msg.ptr2, nlen2, sender);
            break;
        case MSG_MKDIR:
            reply = do_mkdir(cwd, path1);
            break;
        case MSG_RMDIR:
            reply = do_rmdir(cwd, path1);
            break;
        case MSG_CHDIR:
            reply = do_chdir(cwd, path1);
            break;
        case MSG_STAT:
            reply = do_stat(cwd, path1, msg.ptr2, sender);
            break;
        case MSG_SYNC:
            do_sync();
            reply = make_ok(0);
            break;
        case MSG_SHUTDOWN:
            do_sync();
            TracePrintf(0, "YFS: shutting down\n");
            Reply(&reply, sender);
            Exit(0);
            break;
        default:
            reply = make_error();
            break;
        }

        Reply(&reply, sender);
    }

    do_sync();
    Exit(0);
    return 0;
}

