   101→/* Look up a block in the cache; returns entry or NULL */
   102→static struct bcache_entry *
   103→bcache_lookup(int blocknum)
   104→{
   105→    int h = blocknum % BCACHE_HASH;
   106→    struct bcache_entry *e = bhash[h];
   107→    while (e) {
   108→        if (e->blocknum == blocknum) return e;
   109→        e = e->hash_next;
   110→    }
   111→    return NULL;
   112→}
   113→
   114→/*
   115→ * Get or load a block into the cache. Returns pointer to the 512-byte data.
   116→ * Never returns NULL (fatal if disk read fails).
   117→ */
   118→static char *
   119→get_block(int blocknum)
   120→{
   121→    struct bcache_entry *e;
   122→    int h;
   123→
   124→    e = bcache_lookup(blocknum);
   125→    if (e) {
   126→        blru_touch(e);
   127→        return e->data;
   128→    }
   129→
   130→    /* Need a slot */
   131→    if (bcache_used < BLOCK_CACHESIZE) {
   132→        /* find an unused slot */
   133→        int i;
   134→        for (i = 0; i < BLOCK_CACHESIZE; i++) {
   135→            if (bcache[i].blocknum == 0) {
   136→                e = &bcache[i];
   137→                break;
   138→            }
   139→        }
   140→        bcache_used++;
   141→    } else {
   142→        /* evict LRU */
   143→        e = blru_tail;
   144→        bflush(e);
   145→        bhash_remove(e);
   146→        blru_remove(e);
   147→    }
   148→
   149→    /* Load from disk */
   150→    e->blocknum   = blocknum;
   151→    e->dirty      = 0;
   152→    e->hash_next  = NULL;
   153→    e->lru_prev   = NULL;
   154→    e->lru_next   = NULL;
   155→    ReadSector(blocknum, e->data);
   156→
   157→    h = blocknum % BCACHE_HASH;
   158→    e->hash_next = bhash[h];
   159→    bhash[h] = e;
   160→    blru_push_head(e);
   161→    return e->data;
   162→}
