   487→    char *blk1;
   488→
   489→    /* Read superblock (block 1) */
   490→    blk1 = get_block(1);
   491→    hdr  = (struct fs_header *)blk1;
   492→    num_blocks  = hdr->num_blocks;
   493→    num_inodes  = hdr->num_inodes;
   494→
   495→    /* First data block */
   496→    first_data_blk = 1 + (num_inodes + 1 + INODES_PER_BLOCK - 1)
   497→                           / INODES_PER_BLOCK;
   498→
   499→    TracePrintf(0, "YFS: num_blocks=%d num_inodes=%d first_data_blk=%d\n",
   500→                num_blocks, num_inodes, first_data_blk);
   501→
   502→    /* Allocate arrays */
   503→    free_blocks = (int *)malloc(num_blocks * sizeof(int));
   504→    free_inodes = (int *)malloc((num_inodes + 1) * sizeof(int));
   505→    used_bitmap = (char *)malloc(num_blocks);
   506→    memset(used_bitmap, 0, num_blocks);
   507→    free_block_cnt = 0;
   508→    free_inode_cnt = 0;
   509→
   510→    /* Mark inode-region blocks as used */
   511→    for (i = 1; i < first_data_blk; i++)
   512→        used_bitmap[i] = 1;
   513→
   514→    /* Scan inodes: build free inode list + mark data blocks in use */
   515→    for (i = 1; i <= num_inodes; i++) {
   516→        struct inode *ip = get_inode(i);
   517→        if (ip->type == INODE_FREE) {
   518→            push_free_inode(i);
   519→        } else {
   520→            mark_inode_blocks_used(i, used_bitmap);
   521→        }
   522→    }
   523→
   524→    /* Build free block list */
   525→    for (i = first_data_blk; i < num_blocks; i++) {
   526→        if (!used_bitmap[i])
   527→            push_free_block(i);
   528→    }
   529→
   530→    free(used_bitmap);
   531→    TracePrintf(0, "YFS: free_blocks=%d free_inodes=%d\n",
   532→                free_block_cnt, free_inode_cnt);
   533→}
