   614→/* =========================================================================
   615→ * Directory helpers
   616→ * ========================================================================= */
   617→
   618→/*
   619→ * Look up 'name' (up to namelen chars, or null-terminated) in directory inum.
   620→ * Returns the child inum, or 0 if not found.
   621→ */
   622→static int
   623→dir_lookup(int dir_inum, const char *name, int namelen)
   624→{
   625→    struct inode *dir_ip = get_inode(dir_inum);
   626→    int total = dir_ip->size;
   627→    int pos = 0;
   628→
   629→    /* namelen <= 0 means null-terminated */
   630→    if (namelen <= 0) namelen = (int)strlen(name);
   631→    if (namelen > DIRNAMELEN) return 0;
   632→
   633→    while (pos < total) {
   634→        int bidx = pos / BLOCKSIZE;
   635→        int off  = pos % BLOCKSIZE;
   636→        int blk  = get_file_blocknum(dir_ip, bidx);
   637→
   638→        /* If no block (hole) - shouldn't happen in dirs but handle it */
   639→        if (blk == 0) {
   640→            pos += BLOCKSIZE - off;
   641→            continue;
   642→        }
   643→        char *bdata = get_block(blk);
   644→        while (off + (int)sizeof(struct dir_entry) <= BLOCKSIZE
   645→               && pos < total) {
   646→            struct dir_entry *de = (struct dir_entry *)(bdata + off);
   647→            if (de->inum != 0) {
   648→                /* Compare name up to DIRNAMELEN chars */
   649→                int match = 1;
   650→                int i;
   651→                for (i = 0; i < namelen; i++) {
   652→                    if (i >= DIRNAMELEN || de->name[i] != name[i]) {
   653→                        match = 0; break;
   654→                    }
   655→                }
   656→                /* also ensure de->name ends at or after namelen */
   657→                if (match && namelen < DIRNAMELEN
   658→                    && de->name[namelen] != '\0')
   659→                    match = 0;
   660→                if (match) return de->inum;
   661→            }
   662→            off += sizeof(struct dir_entry);
   663→            pos += sizeof(struct dir_entry);
   664→        }
   665→        /* If block not fully consumed, skip to next block */
   666→        if (off < BLOCKSIZE && pos < total) {
   667→            int skip = BLOCKSIZE - off;
   668→            pos += skip;
   669→        }
   670→    }
   671→    return 0;
   672→}
