   674→/*
   675→ * Add a directory entry for (name, child_inum) into directory dir_inum.
   676→ * Reuses a free slot (inum==0) if available, else appends.
   677→ * Returns 0 on success, ERROR on failure.
   678→ */
   679→static int
   680→dir_add(int dir_inum, const char *name, int namelen, int child_inum)
   681→{
   682→    struct inode *dir_ip = get_inode(dir_inum);
   683→    int total = dir_ip->size;
   684→    int pos = 0;
   685→
   686→    if (namelen <= 0) namelen = (int)strlen(name);
   687→    if (namelen > DIRNAMELEN) return ERROR;
   688→
   689→    /* Search for a free slot */
   690→    while (pos < total) {
   691→        int bidx = pos / BLOCKSIZE;
   692→        int off  = pos % BLOCKSIZE;
   693→        int blk  = get_file_blocknum(dir_ip, bidx);
   694→        if (blk == 0) { pos += BLOCKSIZE - off; continue; }
   695→        char *bdata = get_block(blk);
   696→        while (off + (int)sizeof(struct dir_entry) <= BLOCKSIZE
   697→               && pos < total) {
   698→            struct dir_entry *de = (struct dir_entry *)(bdata + off);
   699→            if (de->inum == 0) {
   700→                /* Reuse this free slot */
   701→                memset(de, 0, sizeof(struct dir_entry));
   702→                de->inum = (short)child_inum;
   703→                memcpy(de->name, name, namelen);
   704→                mark_block_dirty(blk);
   705→                return 0;
   706→            }
   707→            off += sizeof(struct dir_entry);
   708→            pos += sizeof(struct dir_entry);
   709→        }
   710→        if (off < BLOCKSIZE && pos < total) pos += BLOCKSIZE - off;
   711→    }
   712→
   713→    /* Append a new entry */
   714→    int bidx = total / BLOCKSIZE;
   715→    int off  = total % BLOCKSIZE;
   716→    int blk  = get_or_alloc_file_block(dir_inum, dir_ip, bidx);
   717→    if (blk == 0) return ERROR;
   718→    char *bdata = get_block(blk);
   719→    struct dir_entry *de = (struct dir_entry *)(bdata + off);
   720→    memset(de, 0, sizeof(struct dir_entry));
   721→    de->inum = (short)child_inum;
   722→    memcpy(de->name, name, namelen);
   723→    mark_block_dirty(blk);
   724→    dir_ip->size += sizeof(struct dir_entry);
   725→    mark_inode_dirty(dir_inum);
   726→    return 0;
   727→}
