   777→/* =========================================================================
   778→ * Path resolution (namei)
   779→ * ========================================================================= */
   780→
   781→/*
   782→ * Parse next path component from *path into component[].
   783→ * Advances *path past the component and any following slashes.
   784→ * Returns length of component (0 = done, end of path).
   785→ */
   786→static int
   787→next_component(const char **path, char *component)
   788→{
   789→    /* skip leading slashes */
   790→    while (**path == '/') (*path)++;
   791→    if (**path == '\0') return 0;
   792→
   793→    int len = 0;
   794→    while (**path != '/' && **path != '\0') {
   795→        if (len < DIRNAMELEN)
   796→            component[len] = **path;
   797→        len++;
   798→        (*path)++;
   799→    }
   800→    if (len < DIRNAMELEN) component[len] = '\0';
   801→    else component[DIRNAMELEN] = '\0';
   802→
   803→    /* Skip trailing slashes — if there are trailing slashes, treat as "." */
   804→    /* Note: we handle trailing slash in namei by detecting empty component */
   805→    return len;
   806→}
   807→
   808→#define NAMEI_LOOKUP   0  /* don't follow last symlink (for unlink, link, readlink) */
   809→#define NAMEI_FOLLOW   1  /* follow last symlink (open, create, chdir, stat) */
   810→
   811→/*
   812→ * Resolve a path to an inode number.
   813→ *
   814→ *   cwd:        inode of current working directory
   815→ *   path:       the pathname to resolve
   816→ *   parent_out: if non-NULL, receives the parent directory inode
   817→ *   last_name:  if non-NULL, receives the last path component name
   818→ *   last_namelen: receives length of last_name
   819→ *   follow:     NAMEI_FOLLOW or NAMEI_LOOKUP for final component symlink
   820→ *   depth:      symlink recursion depth (caller passes 0)
   821→ *
   822→ * Returns inode number on success, or 0 on "not found",
   823→ * or ERROR (-1) on hard error.
   824→ */
   825→static int
   826→namei(int cwd, const char *path, int *parent_out,
   827→      char *last_name, int *last_namelen,
   828→      int follow, int depth)
   829→{
   830→    int cur_inum;
   831→    char component[DIRNAMELEN + 1];
   832→    const char *p = path;
   833→    int child_inum;
   834→    int prev_inum;
   835→
   836→    if (path == NULL || path[0] == '\0') return ERROR;
   837→    if (depth > MAXSYMLINKS) return ERROR;
   838→
   839→    /* Start from root or cwd */
   840→    if (path[0] == '/') {
   841→        cur_inum = ROOTINODE;
   842→        /* skip leading slashes */
   843→        while (*p == '/') p++;
   844→        if (*p == '\0') {
