  1068→static struct yfs_reply
  1069→do_read(int inum, int reuse, int pos, void *client_buf, int size, int sender)
  1070→{
  1071→    struct inode *ip = get_inode(inum);
  1072→    if (ip == NULL || ip->type == INODE_FREE) return make_error();
  1073→    if (ip->reuse != reuse) return make_error();
  1074→    if (ip->type == INODE_SYMLINK) return make_error();
  1075→
  1076→    if (size < 0) return make_error();
  1077→    if (pos < 0) return make_error();
  1078→
  1079→    int avail = ip->size - pos;
  1080→    if (avail <= 0) {
  1081→        struct yfs_reply r = make_ok(0);
  1082→        r.newpos = pos;
  1083→        return r;
  1084→    }
  1085→    if (size > avail) size = avail;
  1086→
  1087→    /* Transfer data block by block using CopyTo */
  1088→    int done = 0;
  1089→    char tmp[BLOCKSIZE];
  1090→    while (done < size) {
  1091→        int bidx  = (pos + done) / BLOCKSIZE;
  1092→        int boff  = (pos + done) % BLOCKSIZE;
  1093→        int chunk = BLOCKSIZE - boff;
  1094→        if (chunk > size - done) chunk = size - done;
  1095→
  1096→        int blk = get_file_blocknum(ip, bidx);
  1097→        if (blk == 0) {
  1098→            /* hole: read zeros */
  1099→            memset(tmp, 0, chunk);
  1100→        } else {
  1101→            char *bdata = get_block(blk);
  1102→            memcpy(tmp, bdata + boff, chunk);
  1103→        }
  1104→        /* Copy chunk to client's buffer */
  1105→        if (CopyTo(sender, (char *)client_buf + done, tmp, chunk) != 0)
  1106→            return make_error();
  1107→        done += chunk;
  1108→    }
  1109→
  1110→    struct yfs_reply r = make_ok(done);
  1111→    r.newpos = pos + done;
  1112→    return r;
  1113→}
