     1→/*
     2→ * iolib.c - YFS client library
     3→ *
     4→ * Maintains per-process state:
     5→ *   - fd table (up to MAX_OPEN_FILES open files)
     6→ *   - current working directory inode number
     7→ *
     8→ * Each function packages a request message and calls Send(-FILE_SERVER, &msg).
     9→ * The reply is received when Send returns.
    10→ */
    11→
    12→#include <string.h>
    13→#include <stdint.h>
    14→
    15→#include <comp421/yalnix.h>
    16→#include <comp421/iolib.h>
    17→#include <comp421/filesystem.h>
    18→
    19→#include "yfs_msg.h"
    20→
    21→/* -----------------------------------------------------------------------
    22→ * Library state
    23→ * ----------------------------------------------------------------------- */
    24→
    25→struct fd_entry {
    26→    int  inum;      /* inode number of the open file */
    27→    int  reuse;     /* reuse count when file was opened */
    28→    int  position;  /* current byte position */
    29→    int  is_open;   /* 1 if slot is in use */
    30→};
    31→
    32→static struct fd_entry fd_table[MAX_OPEN_FILES];
    33→static int cwd_inum = ROOTINODE;   /* current directory inode */
    34→static int lib_initialized = 0;
    35→
    36→static void
    37→lib_init(void)
    38→{
    39→    int i;
    40→    if (lib_initialized) return;
    41→    for (i = 0; i < MAX_OPEN_FILES; i++)
    42→        fd_table[i].is_open = 0;
    43→    cwd_inum = ROOTINODE;
    44→    lib_initialized = 1;
    45→}
    46→
    47→/* Allocate the lowest available fd, return -1 if none available */
    48→static int
    49→alloc_fd(void)
    50→{
    51→    int i;
    52→    lib_init();
    53→    for (i = 0; i < MAX_OPEN_FILES; i++) {
    54→        if (!fd_table[i].is_open)
    55→            return i;
    56→    }
    57→    return -1;
    58→}
    59→
    60→/* Send a request and get back a reply. Returns the reply. */
    61→static struct yfs_reply
    62→do_request(struct yfs_msg *msg)
    63→{
    64→    struct yfs_reply reply;
    65→    memset(&reply, 0, sizeof(reply));
    66→    reply.retval = ERROR;
    67→
    68→    Send(msg, -FILE_SERVER);
    69→    /* After Send returns, the reply has been written into msg's space.
    70→     * Actually, Send overwrites the 32 bytes at msg with the reply. */
    71→    memcpy(&reply, msg, sizeof(reply));
    72→    return reply;
    73→}
    74→
    75→/* -----------------------------------------------------------------------
    76→ * Open
    77→ * ----------------------------------------------------------------------- */
    78→int
    79→Open(char *pathname)
    80→{
    81→    struct yfs_msg msg;
    82→    struct yfs_reply rep;
    83→    int fd;
    84→
    85→    lib_init();
    86→    if (pathname == NULL) return ERROR;
    87→
    88→    fd = alloc_fd();
    89→    if (fd < 0) return ERROR;
    90→
    91→    memset(&msg, 0, sizeof(msg));
    92→    msg.type = MSG_OPEN;
    93→    msg.arg1 = cwd_inum;
    94→    msg.arg2 = (int)strlen(pathname) + 1; /* include null terminator */
    95→    msg.arg3 = 0;
    96→    msg.ptr1 = pathname;
    97→    msg.ptr2 = NULL;
    98→
    99→    rep = do_request(&msg);
   100→    if (rep.retval == ERROR) return ERROR;
   101→
   102→    fd_table[fd].inum     = rep.inum;
   103→    fd_table[fd].reuse    = rep.reuse;
   104→    fd_table[fd].position = 0;
   105→    fd_table[fd].is_open  = 1;
   106→    return fd;
   107→}
   108→
   109→/* -----------------------------------------------------------------------
   110→ * Close
   111→ * ----------------------------------------------------------------------- */
   112→int
   113→Close(int fd)
   114→{
   115→    lib_init();
   116→    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_open)
   117→        return ERROR;
   118→    fd_table[fd].is_open = 0;
   119→    return 0;
   120→}
   121→
   122→/* -----------------------------------------------------------------------
   123→ * Create
   124→ * ----------------------------------------------------------------------- */
   125→int
   126→Create(char *pathname)
   127→{
   128→    struct yfs_msg msg;
   129→    struct yfs_reply rep;
   130→    int fd;
   131→
   132→    lib_init();
   133→    if (pathname == NULL) return ERROR;
   134→
   135→    fd = alloc_fd();
   136→    if (fd < 0) return ERROR;
   137→
   138→    memset(&msg, 0, sizeof(msg));
   139→    msg.type = MSG_CREATE;
   140→    msg.arg1 = cwd_inum;
   141→    msg.arg2 = (int)strlen(pathname) + 1;
   142→    msg.arg3 = 0;
   143→    msg.ptr1 = pathname;
   144→    msg.ptr2 = NULL;
   145→
   146→    rep = do_request(&msg);
   147→    if (rep.retval == ERROR) return ERROR;
   148→
   149→    fd_table[fd].inum     = rep.inum;
   150→    fd_table[fd].reuse    = rep.reuse;
   151→    fd_table[fd].position = 0;
   152→    fd_table[fd].is_open  = 1;
   153→    return fd;
   154→}
   155→
   156→/* -----------------------------------------------------------------------
   157→ * Read
   158→ * ----------------------------------------------------------------------- */
   159→int
   160→Read(int fd, void *buf, int size)
   161→{
   162→    struct yfs_msg msg;
   163→    struct yfs_reply rep;
   164→
   165→    lib_init();
   166→    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_open)
   167→        return ERROR;
   168→    if (buf == NULL || size < 0) return ERROR;
   169→    if (size == 0) return 0;
   170→
   171→    memset(&msg, 0, sizeof(msg));
   172→    msg.type = MSG_READ;
   173→    msg.arg1 = fd_table[fd].inum;
   174→    msg.arg2 = fd_table[fd].reuse;
   175→    msg.arg3 = fd_table[fd].position;
   176→    msg.ptr1 = buf;
   177→    msg.ptr2 = (void *)(intptr_t)size;
   178→
   179→    rep = do_request(&msg);
   180→    if (rep.retval == ERROR) return ERROR;
   181→
   182→    fd_table[fd].position = rep.newpos;
   183→    return rep.retval; /* bytes read */
   184→}
   185→
   186→/* -----------------------------------------------------------------------
   187→ * Write
   188→ * ----------------------------------------------------------------------- */
   189→int
   190→Write(int fd, void *buf, int size)
   191→{
   192→    struct yfs_msg msg;
   193→    struct yfs_reply rep;
   194→
   195→    lib_init();
   196→    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_open)
   197→        return ERROR;
   198→    if (buf == NULL || size < 0) return ERROR;
   199→    if (size == 0) return 0;
   200→
   201→    memset(&msg, 0, sizeof(msg));
   202→    msg.type = MSG_WRITE;
   203→    msg.arg1 = fd_table[fd].inum;
   204→    msg.arg2 = fd_table[fd].reuse;
   205→    msg.arg3 = fd_table[fd].position;
   206→    msg.ptr1 = buf;
   207→    msg.ptr2 = (void *)(intptr_t)size;
   208→
   209→    rep = do_request(&msg);
   210→    if (rep.retval == ERROR) return ERROR;
   211→
   212→    fd_table[fd].position = rep.newpos;
   213→    return rep.retval; /* bytes written */
   214→}
   215→
   216→/* -----------------------------------------------------------------------
   217→ * Seek
   218→ * ----------------------------------------------------------------------- */
   219→int
   220→Seek(int fd, int offset, int whence)
   221→{
   222→    struct yfs_msg msg;
   223→    struct yfs_reply rep;
   224→
   225→    lib_init();
   226→    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_open)
   227→        return ERROR;
   228→
   229→    memset(&msg, 0, sizeof(msg));
   230→    msg.type = MSG_SEEK;
   231→    msg.arg1 = fd_table[fd].inum;
   232→    msg.arg2 = fd_table[fd].reuse;
   233→    msg.arg3 = fd_table[fd].position;
   234→    msg.ptr1 = (void *)(intptr_t)offset;
   235→    msg.ptr2 = (void *)(intptr_t)whence;
   236→
   237→    rep = do_request(&msg);
   238→    if (rep.retval == ERROR) return ERROR;
   239→
   240→    fd_table[fd].position = rep.retval;
   241→    return rep.retval;
   242→}
